import './index.css';

import {
  useEffect,
  useState
} from 'react';

import Header
from '../../components/common/Header';

import {
  getSubjects
} from '../../services/subjectService';

function StudentSubjects() {

  // ======================================
  // STATES
  // ======================================

  const [subjects, setSubjects] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  // ======================================
  // LOAD SUBJECTS
  // ======================================

  useEffect(() => {

    loadSubjects();

  }, []);

  const loadSubjects =
    async () => {

    try {

      const data =
        await getSubjects();

      console.log(data);

      setSubjects(data);

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-subjects">

      {/* HEADER */}

      <Header />


      {/* CONTENT */}

      <div className="student-subjects-content">

        {/* TOP */}

        <div className="subjects-top">

          <h1>
            My Subjects
          </h1>

          <p>
            View all enrolled academic subjects
          </p>

        </div>


        {/* LOADING */}

        {

          loading
          ? (

            <div className="loading-box">

              Loading Subjects...

            </div>

          )
          : (

            <div className="subject-grid">

              {

                subjects.length > 0
                ? (

                  subjects.map((subject) => (

                    <div
                      key={subject.id}
                      className="subject-card"
                    >

                      {/* ICON */}

                      <div className="subject-icon">

                        📘

                      </div>


                      {/* SUBJECT NAME */}

                      <h3>

                        {subject.subject_name}

                      </h3>


                      {/* SUBJECT ID */}

                      <p>

                        <strong>
                          Subject ID:
                        </strong>

                        {' '}

                        {

                          subject.subject_id ||

                          `SUB-${subject.id}`

                        }

                      </p>


                      {/* SEMESTER */}

                      <p>

                        <strong>
                          Semester:
                        </strong>

                        {' '}

                        {subject.semester}

                      </p>

                    </div>

                  ))

                )
                : (

                  <div className="empty-box">

                    No Subjects Available

                  </div>

                )

              }

            </div>

          )

        }

      </div>

    </div>

  );

}

export default StudentSubjects;
